create table dirkspzm32.edi_vda4987_hu (
    document_id          varchar2(32 char) not null enable,
    hug_id               varchar2(32 char) not null enable,
    hu_id                varchar2(32 char) not null enable,
    pos                  number(4, 0) not null enable,
    shipping_marks_desc  varchar2(35 char),
    marking_type_code    varchar2(3 char),
    module_name          varchar2(35 char),
    ident_code_qualifier varchar2(3 char),
    label_id             varchar2(9 char),
    object_id            varchar2(22 char),
    lhm_number           varchar2(12 char),
    gross_weight_in_kg   number(7, 0),
    net_weight_in_kg     number(7, 0),
    tare_weight_in_kg    number(7, 0),
    parts_qty_per_hu     number(19, 0)
);

alter table dirkspzm32.edi_vda4987_hu
    add constraint pk_edi_vda4987_hu primary key ( hu_id )
        using index enable;


